{
  "core_question": "How should a 5,000-employee self‑insured employer evaluate the clinical appropriateness, legal compliance, and financial impact of covering GLP‑1 medications for obesity treatment rather than only for type 2 diabetes?",
  "rationale": "The decision requires clinical evidence on efficacy and safety in obesity, legal assessment of ERISA/ACA coverage obligations and anti‑discrimination considerations, and a financial analysis of drug costs versus potential savings.",
  "routes": ["healthcare", "legal", "finance"],
  "sub_questions": {
    "healthcare": "Given the current clinical evidence for semaglutide and tirzepatide in obesity management, what utilization‑management criteria (e.g., BMI thresholds, prior weight‑loss attempts, comorbidity requirements) should a self‑insured employer adopt to ensure appropriate patient selection while maintaining safety?",
    "legal": "Under ERISA and applicable state laws, what legal risks or compliance issues arise when a self‑insured employer expands coverage of GLP‑1 medications from type 2 diabetes to obesity, and how can the plan mitigate potential discrimination or adverse action claims?",
    "finance": "What is the projected budgetary impact over a 3‑year horizon for covering semaglutide and tirzepatide in obesity, including drug acquisition costs, expected rebates, utilization rates, and potential cost offsets from reduced obesity‑related health expenditures?"
  },
  "requires_recency_disclosure": true,
  "recency_notes": "Drug pricing, rebate structures, and payer coverage policies for GLP‑1s may have changed after 2024; evolving clinical guidelines for obesity use of semaglutide and tirzepatide could also be updated."
}
